form:Form.form:Scripts:
		function Validar()
{                                          
	var param= new NomadXML("PARAM");
	param.SetAttr("oi_personal_emp",Ctrl("oi_personal_emp").GetXValue());

	var np = new NomadProxy();
	var nSQL = np.SQLService();               

	var result = nSQL.GetOBJ(Ctrl("main").getResource("QRY_AFIP"), param.ToString()); 

	if(result.l_egreso_afip && result.l_egreso_afip.toString()==1 && Ctrl("c_egreso_afip").GetXValue()=="")
		{
			alert("Es requerido el número de egreso de Afip para la Empresa a la cual pertenece el Legajo.");  
			Ctrl("c_egreso_afip").SetFocus();
			return false;
		}	
	else
		return true;
}             

function ValidarNum()
{   
	if(Validar())
	{
		var numero = Ctrl("c_egreso_afip").GetXValue();       

		if(numero!="" && (!/^([0-9])*$/.test(numero)))
			{
				alert("El valor del campo 'Número de Egreso AFIP' debe ser un número entero");
				Ctrl("c_egreso_afip").SetFocus();
				return false;
			}	
		else
			return true;
	}
	else
		return false;
}
